using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configure AI client ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// --- Register tools ---
var notebook = new ResearchNotebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearch.SearchAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.ReadNotes),
};

// --- Get topic from user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nрџ”Ќ Researching: {topic}\n");

// --- Run the agent ---
List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the topic the
        user gives you and produce a well-organized summary.

        Follow this workflow:
        1. Perform 2-3 web searches with varied queries to gather broad information.
        2. After each search, save the important findings as a note using add_note.
        3. When you have enough material, call read_notes to review everything.
        4. Produce a final, comprehensive summary that synthesizes all your notes.
           Cite the source URLs inline where possible.

        Be thorough but concise.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}"),
];

var options = new ChatOptions { Tools = tools };

ChatResponse response = await client.GetResponseAsync(messages, options);

Console.WriteLine("\nрџ“‹ Research Summary");
Console.WriteLine(new string('в”Ђ', 60));
Console.WriteLine(response.Text);

// Show collected notes
string notes = notebook.ReadNotes();
if (!notes.StartsWith("No notes"))
{
    Console.WriteLine($"\nрџ“ќ Collected Notes");
    Console.WriteLine(new string('в”Ђ', 60));
    Console.WriteLine(notes);
}

// в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
// Tool implementations
// в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

/// <summary>Simulated web search tool. Replace the body with a real search API
/// (e.g., Bing Web Search, Google Custom Search) for production use.</summary>
static class WebSearch
{
    [Description("Search the web for information. Returns titles, snippets, and URLs.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  рџЊђ Searching: \"{query}\"");
        await Task.Delay(300); // simulate network latency

        // In production, call a real search API here.
        return $"""
            Search results for: "{query}"

            1. Title: "{query} - Overview"
               URL: https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}
               Snippet: A comprehensive overview covering the history, core concepts,
               and modern developments of {query}.

            2. Title: "In-Depth Analysis of {query}"
               URL: https://example.com/research/{Uri.EscapeDataString(query)}
               Snippet: An expert analysis including recent peer-reviewed studies,
               key statistics, and emerging trends related to {query}.

            3. Title: "Latest News: {query}"
               URL: https://example.com/news/{Uri.EscapeDataString(query)}
               Snippet: Recent developments, breakthroughs, and industry perspectives
               on {query} as of 2026.

            (Note: These are simulated results. Integrate a real search API for
            production use.)
            """;
    }
}

/// <summary>In-memory notebook that the agent uses to collect research findings.</summary>
class ResearchNotebook
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    [Description("Save a research note for later reference.")]
    public string AddNote(
        [Description("Short title for the note")] string title,
        [Description("The note content")] string content)
    {
        _notes.Add((title, content, DateTime.UtcNow));
        Console.WriteLine($"  рџ“ќ Note saved: \"{title}\"");
        return $"Note \"{title}\" saved successfully.";
    }

    [Description("Read all previously saved research notes.")]
    public string ReadNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note {i + 1}: {n.Title} ---\n{n.Content}\n[Saved at {n.Timestamp:HH:mm:ss UTC}]"));
    }
}

